mapper.select:
select case when sum(records_all) is null then 0 else sum(records_all) end as recordAll
    from ()
   where dt >= #{minDt,jdbcType=VARCHAR} and dt < #{maxDt,jdbcType=VARCHAR}

select count(distinct tablename_ch)
    from ()
   where dt = #{dt,jdbcType=VARCHAR}

select dt, sum(records_all) as allCount
  from ()
 where dt >= #{minDt,jdbcType=VARCHAR}
   and dt < #{maxDt,jdbcType=VARCHAR}

       and operator_net = #{operatorNet,jdbcType=VARCHAR}


       and (upper(data_type) = upper(#{searchName,jdbcType=VARCHAR}) or upper(tablename_ch) = upper(#{searchName,jdbcType=VARCHAR}))


       and upper(citycode) = upper(#{areaName,jdbcType=VARCHAR})


       and upper(operator_net) = upper(#{operatorName,jdbcType=VARCHAR})


       and upper(data_source) = upper(#{networkTypeName,jdbcType=VARCHAR})

 group by dt order by dt

select citycode as city,operator_net as operatorNet, sum(records_all) as allCount
  from ()
 where dt >= #{minDt,jdbcType=VARCHAR}
   and dt < #{maxDt,jdbcType=VARCHAR}
   and citycode != '-'

       and (upper(data_type) = upper(#{searchName,jdbcType=VARCHAR}) or upper(tablename_ch) = upper(#{searchName,jdbcType=VARCHAR}))


       and upper(citycode) = upper(#{areaName,jdbcType=VARCHAR})


       and upper(operator_net) = upper(#{operatorName,jdbcType=VARCHAR})


       and upper(data_source) = upper(#{networkTypeName,jdbcType=VARCHAR})

 group by citycode,operator_net

select tablename_ch as dataClass, sum(records_all) as dataCount
  from ()
 where dt >= #{minDt,jdbcType=VARCHAR}
   and dt < #{maxDt,jdbcType=VARCHAR}

       and (upper(data_type) = upper(#{searchName,jdbcType=VARCHAR}) or upper(tablename_ch) = upper(#{searchName,jdbcType=VARCHAR}))


       and upper(citycode) = upper(#{areaName,jdbcType=VARCHAR})


       and upper(operator_net) = upper(#{operatorName,jdbcType=VARCHAR})


       and upper(data_source) = upper(#{networkTypeName,jdbcType=VARCHAR})

 group by tablename_ch

select valtext as eventClass, sum(records_all) as dataCount
  from ()
 where dt >= #{minDt,jdbcType=VARCHAR}
   and dt < #{maxDt,jdbcType=VARCHAR}

       and (upper(data_type) = upper(#{searchName,jdbcType=VARCHAR}) or upper(tablename_ch) = upper(#{searchName,jdbcType=VARCHAR}))


       and upper(citycode) = upper(#{areaName,jdbcType=VARCHAR})


       and upper(operator_net) = upper(#{operatorName,jdbcType=VARCHAR})


       and upper(data_source) = upper(#{networkTypeName,jdbcType=VARCHAR})

 group by valtext

select valtext as appClass, sum(records_all) as dataCount
  from ()
 where dt >= #{minDt,jdbcType=VARCHAR}
   and dt < #{maxDt,jdbcType=VARCHAR}

       and (upper(data_type) = upper(#{searchName,jdbcType=VARCHAR}) or upper(tablename_ch) = upper(#{searchName,jdbcType=VARCHAR}))


       and upper(citycode) = upper(#{areaName,jdbcType=VARCHAR})


       and upper(operator_net) = upper(#{operatorName,jdbcType=VARCHAR})


       and upper(data_source) = upper(#{networkTypeName,jdbcType=VARCHAR})

 group by valtext
